mapper.select:
SELECT ID, PLAN_CODE, PLAN_NAME, ROUTE_ID, PATROL_TYPE, INITIAL_DATE, SET_DATE, IS_SINGLE, PATROL_ID, PATROL_NAME, RECENTLY_TASK_DATE, STATUS, CREATE_BY, CREATE_TIME, UPDATE_BY, UPDATE_TIME, TIME_LIMIT FROM E_PATROL_PLAN WHERE 1 = 1
AND PLAN_CODE LIKE #{planCode}
AND PLAN_NAME LIKE #{planName}
AND ROUTE_ID = #{routeId}
AND PATROL_TYPE = #{patrolType}

mapper.insert:
INSERT INTO E_PATROL_TASK( ID, PLAN_ID, ROUTE_ID, PATROL_ID, PATROL_NAME, START_DATE, END_DATE, STATUS, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id,jdbcType=BIGINT}, #{item.planId,jdbcType=VARCHAR}, #{item.routeId,jdbcType=VARCHAR}, #{item.patrolId,jdbcType=BIGINT}, #{item.patrolName,jdbcType=VARCHAR}, #{item.startDate,jdbcType=TIMESTAMP}, #{item.endDate,jdbcType=TIMESTAMP}, #{item.status,jdbcType=BIGINT}, #{item.createBy,jdbcType=BIGINT}, #{item.createByName,jdbcType=VARCHAR}, #{item.createTime,jdbcType=TIMESTAMP}
from dual
)

INSERT INTO E_PATROL_TASK_SUB( ID, PARENT_ID, EQUIP_ID, EQUIP_NAME, STATUS , CHECK_CONTENT, QUALIFY_CONDITION, CHECK_METHOD, IS_ABNORMAL, IS_REPAIR )
(
select #{item.id}, #{item.parentId}, #{item.equipId}, #{item.equipName}, #{item.status}, #{item.checkContent}, #{item.qualifyCondition}, #{item.checkMethod}, #{item.isAbnormal}, #{item.isRepair}
from dual
)

mapper.update:
BEGIN

    UPDATE E_PATROL_PLAN
    SET
    RECENTLY_TASK_DATE = #{item.recentlyTaskDate}
    WHERE
    ID = #{item.id};

END;
